import{_ as e,o as s,c as i,a2 as o}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Super Admin","description":"","frontmatter":{},"headers":[],"relativePath":"es/features/super-admin.md","filePath":"es/features/super-admin.md"}'),n={name:"es/features/super-admin.md"};function r(t,a,l,c,d,p){return s(),i("div",null,[...a[0]||(a[0]=[o(`<h1 id="super-admin" tabindex="-1">Super Admin <a class="header-anchor" href="#super-admin" aria-label="Permalink to &quot;Super Admin&quot;">​</a></h1><p>El rol <code>super_admin</code> se crea automáticamente mediante <code>clearance:install</code> y se mantiene sincronizado con todos los permisos <code>clearance-*</code>.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install and make user ID 1 a super admin</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user=1</span></span></code></pre></div><p>Consulta la <a href="/clearance-docs/es/guide/installation.html">guía de Instalación</a> y la <a href="/clearance-docs/es/api/artisan-commands.html">referencia de comandos Artisan</a> para la lista completa de flags del instalador.</p><h2 id="bypass-de-gate-opcional" tabindex="-1">Bypass de Gate (opcional) <a class="header-anchor" href="#bypass-de-gate-opcional" aria-label="Permalink to &quot;Bypass de Gate (opcional)&quot;">​</a></h2><p><code>super_admin_gate_bypass</code> controla si el rol <code>super_admin</code> evita todas las comprobaciones <code>can()</code> / <code>Gate::allows()</code> / de política de Laravel globalmente, mediante un hook <code>Gate::before()</code>. Predeterminado: <code>false</code>. El bypass es opcional. Para activarlo:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;super_admin_gate_bypass&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">De alcance global, no limitado al panel</p><p>Cuando está activado, cualquier usuario que posea <code>super_admin</code> evita <strong>todas</strong> las comprobaciones de Gate en toda la aplicación - no solo las comprobaciones del panel de Clearance. Esto afecta a cada <code>can()</code>, <code>Gate::allows()</code>, y comprobación de política en tu aplicación, no solo a las que Clearance define. Para un alcance más limitado, déjalo desactivado y otorga permisos explícitamente en su lugar.</p></div><h2 id="deteccion-de-alias" tabindex="-1">Detección de alias <a class="header-anchor" href="#deteccion-de-alias" aria-label="Permalink to &quot;Detección de alias&quot;">​</a></h2><p>Si tu base de datos ya contiene un rol llamado <code>super_admin</code>, <code>superadmin</code>, <code>super-admin</code>, <code>root</code>, u <code>owner</code>, el instalador lo detecta y te solicita interactivamente promoverlo o crear un <code>super_admin</code> independiente. Usa <code>--super-admin-role=NAME</code> para omitir el prompt:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --super-admin-role=owner</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">La promoción no es destructiva</p><p>La promoción renombra el rol en su lugar - todas las asignaciones <code>model_has_roles</code> existentes se preservan vía la FK en <code>role_id</code>. Ningún usuario pierde su asignación de rol existente durante la promoción.</p></div><h2 id="acceso-al-panel-y-permisos-de-escritura-granulares" tabindex="-1">Acceso al panel y permisos de escritura granulares <a class="header-anchor" href="#acceso-al-panel-y-permisos-de-escritura-granulares" aria-label="Permalink to &quot;Acceso al panel y permisos de escritura granulares&quot;">​</a></h2><p>Navega a <code>/clearance</code> tras la instalación. El acceso de lectura a todo el panel requiere el permiso <code>clearance-access</code>, verificado vía <code>can()</code>, nunca <code>hasRole()</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>Las operaciones de escritura en cada sección están controladas por un permiso dedicado y delegable - todos creados por <code>clearance:install</code> y asignados a <code>super_admin</code>:</p><table tabindex="0"><thead><tr><th>Permiso</th><th>Controla</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>Crear / editar / eliminar permisos</td></tr><tr><td><code>clearance-roles-write</code></td><td>Crear / editar / eliminar roles y sus asignaciones de permisos</td></tr><tr><td><code>clearance-guards-write</code></td><td>Crear / editar / eliminar guards</td></tr><tr><td><code>clearance-settings-write</code></td><td>Editar metadatos de visualización, iconos, colores, rol predeterminado</td></tr><tr><td><code>clearance-users-write</code></td><td>Asignar / eliminar roles para un usuario específico</td></tr></tbody></table><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Grant a user write access to roles only:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-roles-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Otorgar acceso limitado</p><p>Combina <code>clearance-access</code> con exactamente un permiso <code>clearance-{section}-write</code> para dar a un usuario (digamos, un líder de equipo) acceso de escritura a una sola sección del panel - roles, por ejemplo - sin exponer configuración, guards, o gestión de usuarios.</p></div><p>Si una fila de permiso granular no existe en absoluto en la base de datos (un estado heredado previo a la siembra), la comprobación recurre a <code>clearance-access</code> por compatibilidad hacia atrás. En cualquier instancia que haya ejecutado <code>clearance:install</code>, este fallback nunca se activa.</p><h2 id="permisos-clearance-reservados" tabindex="-1">Permisos <code>clearance-*</code> reservados <a class="header-anchor" href="#permisos-clearance-reservados" aria-label="Permalink to &quot;Permisos \`clearance-*\` reservados&quot;">​</a></h2><p>Los permisos <code>clearance-*</code> están reservados: no pueden crearse, renombrarse, eliminarse, ni añadirse a ningún rol excepto a través del propio flujo de instalación del paquete - ni siquiera por un actor <code>super_admin</code> para el propio rol <code>super_admin</code>.</p><h2 id="proximos-pasos" tabindex="-1">Próximos pasos <a class="header-anchor" href="#proximos-pasos" aria-label="Permalink to &quot;Próximos pasos&quot;">​</a></h2><ul><li><a href="/clearance-docs/es/features/permissions.html">Permisos</a> - el panel general de CRUD de permisos (excluye <code>clearance-*</code>).</li><li><a href="/clearance-docs/es/features/roles.html">Roles</a> - asignar permisos <code>clearance-*-write</code> a un rol personalizado.</li><li><a href="/clearance-docs/es/guide/security.html">Seguridad</a> - el modelo completo de escalada de privilegios y techos.</li></ul>`,24)])])}const m=e(n,[["render",r]]);export{u as __pageData,m as default};
